// ------------------------------------------------------------
// State
// ------------------------------------------------------------
let currentEpisodeIndex = -1;
let mode = localStorage.getItem("readerMode") || "scroll"; // scroll | book
let pages = [];
let pageIndex = 0;
let animLock = false;

// Reader preference state
const DEFAULT_READER_PREFS = Object.freeze({ font: 16, line: 2.38 });
const READER_PREF_KEY = "novel_reader_visual_prefs_v3";
let readerPrefs = loadReaderPrefs();

function loadReaderPrefs() {
  try {
    const raw = localStorage.getItem(READER_PREF_KEY);
    const obj = raw ? JSON.parse(raw) : {};
    return {
      font: Number.isFinite(obj.font) ? obj.font : DEFAULT_READER_PREFS.font,
      line: Number.isFinite(obj.line) ? obj.line : DEFAULT_READER_PREFS.line,
    };
  } catch {
    return { ...DEFAULT_READER_PREFS };
  }
}

function saveReaderPrefs() {
  try { localStorage.setItem(READER_PREF_KEY, JSON.stringify(readerPrefs)); } catch {}
}

function applyReaderPrefs(reflow = false) {
  readerPrefs.font = clamp(readerPrefs.font, 15, 21);
  readerPrefs.line = Math.max(1.8, Math.min(2.6, Math.round(readerPrefs.line * 100) / 100));

  document.documentElement.style.setProperty("--readerFont", `${readerPrefs.font}px`);
  document.documentElement.style.setProperty("--readerLine", String(readerPrefs.line));

  if (readerSizeLabel) readerSizeLabel.textContent = `${readerPrefs.font}px`;
  if (readerLineLabel) readerLineLabel.textContent = `행간 ${readerPrefs.line.toFixed(1)}`;

  saveReaderPrefs();

  if (reflow && mode === "book" && currentEpisodeIndex >= 0) {
    const keep = pageIndex;
    requestAnimationFrame(() => {
      buildPages();
      renderPage(clamp(keep, 0, Math.max(0, pages.length - 1)));
    });
  }
}

// ------------------------------------------------------------
// LocalStorage (per-episode last page)
// ------------------------------------------------------------
const LS_KEY = "novel_reader_last_page_v1";
function loadLastPage(epId) {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (!raw) return 0;
    const obj = JSON.parse(raw);
    const v = obj?.[epId];
    return Number.isFinite(v) ? v : 0;
  } catch {
    return 0;
  }
}
function saveLastPage(epId, idx) {
  try {
    const raw = localStorage.getItem(LS_KEY);
    const obj = raw ? JSON.parse(raw) : {};
    obj[epId] = idx;
    localStorage.setItem(LS_KEY, JSON.stringify(obj));
  } catch {}
}

// ------------------------------------------------------------
// Sentence-based tokenization + natural line breaks
// ------------------------------------------------------------
const FULLWIDTH_INDENT = "　";
const LEADING_INDENT_RE = /^[\u3000 \t]+/;

const SCENE_BREAK = "\n\n\n";
const SCENE_BREAK_TOKEN = "\uE000_SCENE_BREAK_\uE000";

function normalizeReaderContent(content) {
  const normalized = String(content ?? "")
    .replace(/\\n/g, "\n")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    // 줄바꿈 3번 이상은 장면 전환으로 보고 반드시 보존합니다.
    // 기존 코드가 \n\n\n도 \n + 들여쓰기로 접어버려 책 모드에서 장면 여백이 사라졌습니다.
    .replace(/\n[ \t\u3000]*\n[ \t\u3000]*\n(?:[ \t\u3000]*\n)*/g, SCENE_BREAK_TOKEN)
    // 줄바꿈 2번은 일반 문단 구분으로 보고 한 줄 + 전각 공백 들여쓰기로 정리합니다.
    .replace(/\n[ \t\u3000]*\n/g, "\n" + FULLWIDTH_INDENT)
    .replaceAll(SCENE_BREAK_TOKEN, SCENE_BREAK);

  return normalized
    .split("\n")
    .map((line, index) => {
      if (!line.trim()) return "";
      const rightTrimmed = line.replace(/[ \t]+$/g, "");
      if (index === 0) return rightTrimmed;
      if (rightTrimmed.startsWith(FULLWIDTH_INDENT)) return rightTrimmed;
      return FULLWIDTH_INDENT + rightTrimmed.replace(/^[ \t]+/g, "");
    })
    .join("\n");
}


function splitSentences(line) {
  const raw = String(line ?? "").replace(/[ \t]+$/g, "");
  const leading = raw.match(LEADING_INDENT_RE)?.[0] ?? "";
  const body = raw.slice(leading.length).trim();
  if (!body) return [];
  const matches = body.match(/[^.!?…]+[.!?…]+|[^.!?…]+$/g);
  return (matches || [])
    .map((x, index) => `${index === 0 ? leading : ""}${x.trim()}`)
    .filter(Boolean);
}

function tokenizeContent(content) {
  const raw = normalizeReaderContent(content);
  const tokens = [];

  // \n\n\n은 장면 전환 여백으로 보존하고, 일반 \n은 문단 줄바꿈으로 처리합니다.
  // 이렇게 해야 책장 넘김 모드에서도 원고 중간의 큰 호흡이 사라지지 않습니다.
  raw.split(/(\n{2,})/).forEach((part) => {
    if (!part) return;

    if (/^\n{2,}$/.test(part)) {
      tokens.push({ t: part.length >= 3 ? "scene" : "pbr", v: part.length >= 3 ? SCENE_BREAK : "\n\n" });
      return;
    }

    const lines = part.split("\n");
    lines.forEach((line, li) => {
      const sents = splitSentences(line);
      sents.forEach((sent) => tokens.push({ t: "text", v: sent }));
      if (li < lines.length - 1) tokens.push({ t: "br", v: "\n" });
    });
  });

  while (tokens.length && (tokens[0].t === "br" || tokens[0].t === "pbr" || tokens[0].t === "scene")) tokens.shift();
  return tokens;
}


function appendToken(str, tok) {
  if (tok.t === "br" || tok.t === "pbr" || tok.t === "scene") {
    if (!str) return "";

    if (tok.t === "scene") {
      return str.replace(/\n+$/g, "") + SCENE_BREAK;
    }

    if (tok.t === "pbr") {
      if (str.endsWith("\n\n")) return str;
      if (str.endsWith("\n")) return str + "\n";
    }

    return str + tok.v;
  }

  if (!str) return tok.v;
  if (str.endsWith("\n") || str.endsWith("\n\n")) return str + tok.v;
  return str + " " + tok.v;
}


// ------------------------------------------------------------
// Pagination
// ------------------------------------------------------------
function splitByChars(text, maxHeight) {
  const out = [];
  let i = 0;
  while (i < text.length) {
    let lo = i + 40;
    let hi = Math.min(text.length, i + 1400);
    let best = lo;

    while (lo <= hi) {
      const mid = Math.floor((lo + hi) / 2);
      const sub = text.slice(i, mid);
      measureText.textContent = sub;
      if (measureText.getBoundingClientRect().height <= maxHeight) {
        best = mid;
        lo = mid + 1;
      } else hi = mid - 1;
    }

    if (best <= i) best = Math.min(text.length, i + 200);
    out.push(text.slice(i, best).trimEnd());
    i = best;
  }
  return out.filter(Boolean);
}

function buildPages() {
  const ep = NOVEL.episodes[currentEpisodeIndex];
  if (!ep) return;

  pages = [];

  const stageRect = bookStage.getBoundingClientRect();
  const styles = getComputedStyle(document.documentElement);
  const padX = parseFloat(styles.getPropertyValue("--pagePadX")) || 18;
  const padY = parseFloat(styles.getPropertyValue("--pagePadY")) || 18;

  const shellW = Math.max(260, stageRect.width - 28);
  const shellH = Math.max(220, stageRect.height - 84);
  const contentW = Math.max(220, shellW - padX * 2);
  const contentH = Math.max(180, shellH - padY * 2);

  measureBox.style.width = contentW + "px";
  measureText.style.width = contentW + "px";

  // 실제 페이지는 overflow:hidden이라 측정값이 딱 맞으면 마지막 줄 하단이 잘릴 수 있습니다.
  // 한 줄의 약 70%를 안전 여백으로 빼고 페이지를 나눠, 책으로 보기 하단 글자 잘림을 방지합니다.
  const measureStyle = getComputedStyle(measureText);
  const fontPx = parseFloat(measureStyle.fontSize) || readerPrefs.font || 16;
  const lineHeightPx = parseFloat(measureStyle.lineHeight) || fontPx * (readerPrefs.line || 2.2);
  const bottomSafe = Math.max(16, Math.ceil(lineHeightPx * 0.7));
  const usableContentH = Math.max(120, contentH - bottomSafe);

  const tokens = tokenizeContent(ep.content);
  let buf = "";

  for (const tok of tokens) {
    const candidate = appendToken(buf, tok);
    measureText.textContent = candidate;

    if (measureText.getBoundingClientRect().height <= usableContentH) {
      buf = candidate;
      continue;
    }

    if (buf.trim()) {
      pages.push(buf.trimEnd());
      buf = "";
    }

    if (tok.t === "br" || tok.t === "pbr" || tok.t === "scene") continue;

    const single = appendToken("", tok);
    measureText.textContent = single;

    if (measureText.getBoundingClientRect().height <= usableContentH) {
      buf = single;
    } else {
      const chunks = splitByChars(single, usableContentH);
      pages.push(...chunks.slice(0, -1));
      buf = chunks[chunks.length - 1] || "";
    }
  }

  if (buf.trim()) pages.push(buf.trimEnd());
}

// ------------------------------------------------------------
// Render + progress
// ------------------------------------------------------------
function clamp(n, a, b) {
  return Math.max(a, Math.min(b, n));
}

function updateProgressUI() {
  const total = Math.max(1, pages.length);
  const current = clamp(pageIndex, 0, total - 1);
  const percent = Math.round(((current + 1) / total) * 100);

  progressHint.textContent = `페이지: ${current + 1}/${total} · ${percent}%`;

  pageNumberLabel.textContent = `p. ${current + 1} / ${total}`;
  percentLabel.textContent = `${percent}%`;
  progressBarFill.style.width = `${percent}%`;

  const ep = NOVEL.episodes[currentEpisodeIndex];
  if (ep) saveLastPage(ep.id, current);

  const hasPrev = current > 0;
  const hasNext = current < total - 1;
  pagePrevBtn.style.visibility = hasPrev ? "visible" : "hidden";
  pageNextBtn.style.visibility = hasNext ? "visible" : "hidden";
  pagePrevBtn.disabled = !hasPrev;
  pageNextBtn.disabled = !hasNext;
}

function renderPage(idx) {
  if (!pages.length) {
    pageText.textContent = "";
    spreadIndicator.textContent = `0 / 0`;
    progressHint.textContent = `페이지: 0/0 · 0%`;
    pageNumberLabel.textContent = `p. 0 / 0`;
    percentLabel.textContent = `0%`;
    progressBarFill.style.width = `0%`;
    return;
  }
  pageIndex = clamp(idx, 0, pages.length - 1);
  pageText.textContent = pages[pageIndex] ?? "";
  spreadIndicator.textContent = `${pageIndex + 1} / ${pages.length}`;
  updateProgressUI();
}

// ------------------------------------------------------------
// Modes + Mobile auto switching
// ------------------------------------------------------------
function isMobile() {
  return mobileMQ.matches;
}

function setMode(nextMode) {
  mode = nextMode;
  localStorage.setItem("readerMode", mode);
  document.body.dataset.readerMode = mode;

  modeScrollBtn.classList.toggle("active", mode === "scroll");
  modeBookBtn.classList.toggle("active", mode === "book");
  modeScrollBtn.setAttribute("aria-pressed", String(mode === "scroll"));
  modeBookBtn.setAttribute("aria-pressed", String(mode === "book"));

  if (mode === "scroll") {
    resetFlipLayer();
    modeHint.textContent = "모드: 스크롤 읽기";
    epContent.style.display = "block";
    bookWrap.style.display = "none";
    progressHint.textContent = "-";
    mMode.textContent = "스크롤 읽기";
  } else {
    modeHint.textContent = "모드: 책장 넘김";
    epContent.style.display = "none";
    bookWrap.style.display = "block";
    mMode.textContent = "책장 넘김";

    const ep = NOVEL.episodes[currentEpisodeIndex];
    buildPages();
    const last = ep ? loadLastPage(ep.id) : 0;
    renderPage(clamp(last, 0, Math.max(0, pages.length - 1)));
    bookEpLabel.textContent = ep?.title ?? "";
  }
}

function autoModeByDevice() {
  if (currentEpisodeIndex < 0) return;
  if (isMobile()) setMode("scroll");
  else setMode(localStorage.getItem("readerMode") || "book");
}

// ------------------------------------------------------------
// WebGL / Canvas page curl animation
// ------------------------------------------------------------
let flipFallbackTimer = null;
let flipRaf = null;
const reduceMotionMQ = window.matchMedia?.("(prefers-reduced-motion: reduce)");

function cancelFlipTimers() {
  clearTimeout(flipFallbackTimer);
  if (flipRaf) cancelAnimationFrame(flipRaf);
  flipRaf = null;
}

function resetFlipLayer() {
  cancelFlipTimers();
  sheet.removeEventListener("animationend", handleFlipEnd);
  flipLayer.classList.remove("flipNext", "flipPrev", "active", "settling", "webglCurl");
  flipLayer.style.display = "none";
  sheet.style.transform = "";
  sheet.style.transformOrigin = "left center";
  sheetFrontText.textContent = "";
  sheetBackText.textContent = "";
  if (curlCanvas) {
    const ctx2d = curlCanvas.getContext("2d", { willReadFrequently: false });
    if (ctx2d) ctx2d.clearRect(0, 0, curlCanvas.width, curlCanvas.height);
    curlCanvas.style.display = "none";
  }
  animLock = false;
}

function handleFlipEnd() {
  resetFlipLayer();
}

function roundedRectPath(ctx, x, y, w, h, r) {
  const rr = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + rr, y);
  ctx.arcTo(x + w, y, x + w, y + h, rr);
  ctx.arcTo(x + w, y + h, x, y + h, rr);
  ctx.arcTo(x, y + h, x, y, rr);
  ctx.arcTo(x, y, x + w, y, rr);
  ctx.closePath();
}

function getPageRectForCanvas() {
  const rect = pageShell.getBoundingClientRect();
  const dpr = Math.max(1, Math.min(2, window.devicePixelRatio || 1));
  return {
    cssW: Math.max(1, rect.width),
    cssH: Math.max(1, rect.height),
    w: Math.max(1, Math.round(rect.width * dpr)),
    h: Math.max(1, Math.round(rect.height * dpr)),
    dpr
  };
}

function wrapCanvasLine(ctx, text, maxWidth) {
  const out = [];
  const raw = String(text ?? "");
  if (!raw) return [""];

  const leading = raw.match(LEADING_INDENT_RE)?.[0] ?? "";
  const body = raw.slice(leading.length);
  const tokens = body.split(/(\s+)/).filter((v) => v.length);
  let line = leading;

  function pushLongToken(prefix, token) {
    let current = prefix || "";
    for (const ch of token) {
      const trial = current + ch;
      if (current && ctx.measureText(trial).width > maxWidth) {
        out.push(current);
        current = ch;
      } else current = trial;
    }
    return current;
  }

  tokens.forEach((token) => {
    const trial = line + token;
    if (!line || ctx.measureText(trial).width <= maxWidth) {
      line = trial;
      return;
    }

    if (ctx.measureText(token).width > maxWidth) {
      line = pushLongToken(line.trimEnd(), token);
    } else {
      out.push(line.trimEnd());
      line = token.trimStart();
    }
  });

  if (line.trim().length) out.push(line.trimEnd());
  return out.length ? out : [""];
}

function renderPageTexture(text, pageNoText = "") {
  const dims = getPageRectForCanvas();
  const canvas = document.createElement("canvas");
  canvas.width = dims.w;
  canvas.height = dims.h;
  const ctx = canvas.getContext("2d");
  const scale = dims.dpr;
  ctx.scale(scale, scale);

  const w = dims.cssW;
  const h = dims.cssH;
  const styles = getComputedStyle(document.documentElement);
  const fontSize = parseFloat(styles.getPropertyValue("--readerFont")) || 17;
  const lineRatio = parseFloat(styles.getPropertyValue("--readerLine")) || 2;
  const lineH = fontSize * lineRatio;
  const padX = parseFloat(styles.getPropertyValue("--pagePadX")) || 18;
  const padY = parseFloat(styles.getPropertyValue("--pagePadY")) || 18;
  const maxW = w - padX * 2;

  roundedRectPath(ctx, 0, 0, w, h, 18);
  ctx.clip();

  const bg = ctx.createLinearGradient(0, 0, w, h);
  bg.addColorStop(0, "#15130f");
  bg.addColorStop(0.48, "#11100d");
  bg.addColorStop(1, "#0b0a08");
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, w, h);

  const glow = ctx.createRadialGradient(w * .22, h * .02, 0, w * .22, h * .02, Math.max(w, h) * .82);
  glow.addColorStop(0, "rgba(239, 204, 138, .075)");
  glow.addColorStop(.55, "rgba(239, 204, 138, .018)");
  glow.addColorStop(1, "rgba(239, 204, 138, 0)");
  ctx.fillStyle = glow;
  ctx.fillRect(0, 0, w, h);

  ctx.save();
  ctx.globalAlpha = .12;
  ctx.strokeStyle = "rgba(255,255,255,.055)";
  for (let y = 0; y < h; y += 6) {
    ctx.beginPath();
    ctx.moveTo(0, y + .5);
    ctx.lineTo(w, y + .5);
    ctx.stroke();
  }
  ctx.restore();

  ctx.font = `600 ${fontSize}px Pretendard, Apple SD Gothic Neo, Noto Sans KR, system-ui, -apple-system, sans-serif`;
  ctx.fillStyle = "#ebe5d8";
  ctx.textBaseline = "top";

  let y = padY;
  const lines = String(text ?? "").split("\n");
  for (const rawLine of lines) {
    if (rawLine.trim() === "") {
      y += lineH * .72;
      continue;
    }
    const wrapped = wrapCanvasLine(ctx, rawLine, maxW);
    for (const line of wrapped) {
      if (y > h - padY - lineH * .5) break;
      ctx.fillText(line, padX, y);
      y += lineH;
    }
    if (y > h - padY - lineH * .5) break;
  }

  ctx.save();
  ctx.font = `12px system-ui, -apple-system, Segoe UI, Roboto, Apple SD Gothic Neo, Noto Sans KR, sans-serif`;
  ctx.fillStyle = "rgba(235,229,216,.38)";
  ctx.textBaseline = "bottom";
  if (pageNoText) ctx.fillText(pageNoText, padX, h - 12);
  ctx.restore();

  const edge = ctx.createLinearGradient(0, 0, w, 0);
  edge.addColorStop(0, "rgba(255,255,255,.02)");
  edge.addColorStop(.08, "rgba(255,255,255,0)");
  edge.addColorStop(.92, "rgba(0,0,0,0)");
  edge.addColorStop(1, "rgba(0,0,0,.34)");
  ctx.fillStyle = edge;
  ctx.fillRect(0, 0, w, h);

  return canvas;
}

class WebGLPageCurl {
  constructor(canvas) {
    this.canvas = canvas;
    this.gl = null;
    this.program = null;
    this.buffers = null;
    this.texture = null;
    this.ready = false;
    this.cols = 82;
    this.rows = 18;
    this.init();
  }

  init() {
    const gl = this.canvas?.getContext("webgl", { alpha: true, antialias: true, premultipliedAlpha: false }) ||
               this.canvas?.getContext("experimental-webgl", { alpha: true, antialias: true, premultipliedAlpha: false });
    if (!gl) return;
    this.gl = gl;

    const vs = `
      attribute vec2 aPos;
      attribute vec2 aUv;
      uniform float uProgress;
      uniform float uDir;
      varying vec2 vUv;
      varying float vShade;
      varying float vCurl;
      const float PI = 3.141592653589793;

      void main(){
        float u = aPos.x;
        float y = 1.0 - aPos.y * 2.0;
        float p = clamp(uProgress, 0.0, 1.0);
        float bend = sin(p * PI);
        float x0 = u * 2.0 - 1.0;
        float sx;
        float z;
        float curve;

        if (uDir > 0.0) {
          float dx = x0 + 1.0;
          curve = sin(u * PI);
          float theta = -p * PI - bend * 0.92 * curve;
          sx = -1.0 + dx * cos(theta);
          z = dx * sin(theta);
        } else {
          float dx = 1.0 - x0;
          curve = sin((1.0 - u) * PI);
          float theta = p * PI + bend * 0.92 * curve;
          sx = 1.0 - dx * cos(theta);
          z = dx * sin(theta);
        }

        float lift = bend * curve;
        float perspective = 1.0 / (1.0 + z * 0.34);
        float sy = y * perspective * (1.0 + lift * 0.018);
        sx = sx * perspective;

        vUv = aUv;
        vShade = clamp(abs(z) * 0.34 + lift * 0.42, 0.0, 1.0);
        vCurl = lift;
        gl_Position = vec4(sx, sy, 0.0, 1.0);
      }`;

    const fs = `
      precision mediump float;
      uniform sampler2D uTexture;
      uniform float uProgress;
      uniform float uDir;
      varying vec2 vUv;
      varying float vShade;
      varying float vCurl;
      const float PI = 3.141592653589793;

      void main(){
        vec4 tex = texture2D(uTexture, vUv);
        float p = clamp(uProgress, 0.0, 1.0);
        float moving = sin(p * PI);
        float edgeNext = smoothstep(0.72, 1.0, vUv.x);
        float edgePrev = smoothstep(0.72, 1.0, 1.0 - vUv.x);
        float edge = mix(edgePrev, edgeNext, step(0.0, uDir));
        float highlight = edge * moving * 0.22 + vCurl * 0.08;
        float shade = 1.0 - vShade * 0.32 - edge * moving * 0.18;
        tex.rgb = tex.rgb * shade + vec3(0.95, 0.78, 0.45) * highlight;
        tex.a *= smoothstep(1.0, 0.92, p);
        gl_FragColor = tex;
      }`;

    const program = this.createProgram(vs, fs);
    if (!program) return;
    this.program = program;
    this.buffers = this.createMesh(this.cols, this.rows);

    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
    gl.disable(gl.CULL_FACE);
    this.ready = true;
  }

  compile(type, source) {
    const gl = this.gl;
    const shader = gl.createShader(type);
    gl.shaderSource(shader, source);
    gl.compileShader(shader);
    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
      console.warn("Page curl shader error", gl.getShaderInfoLog(shader));
      gl.deleteShader(shader);
      return null;
    }
    return shader;
  }

  createProgram(vsSource, fsSource) {
    const gl = this.gl;
    const vs = this.compile(gl.VERTEX_SHADER, vsSource);
    const fs = this.compile(gl.FRAGMENT_SHADER, fsSource);
    if (!vs || !fs) return null;
    const program = gl.createProgram();
    gl.attachShader(program, vs);
    gl.attachShader(program, fs);
    gl.linkProgram(program);
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
      console.warn("Page curl program error", gl.getProgramInfoLog(program));
      gl.deleteProgram(program);
      return null;
    }
    return program;
  }

  createMesh(cols, rows) {
    const gl = this.gl;
    const vertices = [];
    const indices = [];
    for (let y = 0; y <= rows; y++) {
      for (let x = 0; x <= cols; x++) {
        const u = x / cols;
        const v = y / rows;
        vertices.push(u, v, u, v);
      }
    }
    for (let y = 0; y < rows; y++) {
      for (let x = 0; x < cols; x++) {
        const a = y * (cols + 1) + x;
        const b = a + 1;
        const c = a + cols + 1;
        const d = c + 1;
        indices.push(a, c, b, b, c, d);
      }
    }

    const vbo = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, vbo);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(vertices), gl.STATIC_DRAW);

    const ibo = gl.createBuffer();
    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, ibo);
    gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, new Uint16Array(indices), gl.STATIC_DRAW);

    return { vbo, ibo, count: indices.length };
  }

  resize(width, height, dpr) {
    if (!this.gl) return;
    this.canvas.width = Math.max(1, Math.round(width * dpr));
    this.canvas.height = Math.max(1, Math.round(height * dpr));
    this.canvas.style.width = width + "px";
    this.canvas.style.height = height + "px";
    this.gl.viewport(0, 0, this.canvas.width, this.canvas.height);
  }

  uploadTexture(sourceCanvas) {
    const gl = this.gl;
    if (!this.texture) this.texture = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, this.texture);
    gl.pixelStorei(gl.UNPACK_PREMULTIPLY_ALPHA_WEBGL, false);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, sourceCanvas);
  }

  draw(progress, dir) {
    const gl = this.gl;
    if (!this.ready || !this.texture) return;
    gl.clearColor(0, 0, 0, 0);
    gl.clear(gl.COLOR_BUFFER_BIT);
    gl.useProgram(this.program);

    const stride = 4 * 4;
    gl.bindBuffer(gl.ARRAY_BUFFER, this.buffers.vbo);
    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, this.buffers.ibo);

    const aPos = gl.getAttribLocation(this.program, "aPos");
    const aUv = gl.getAttribLocation(this.program, "aUv");
    gl.enableVertexAttribArray(aPos);
    gl.vertexAttribPointer(aPos, 2, gl.FLOAT, false, stride, 0);
    gl.enableVertexAttribArray(aUv);
    gl.vertexAttribPointer(aUv, 2, gl.FLOAT, false, stride, 2 * 4);

    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, this.texture);
    gl.uniform1i(gl.getUniformLocation(this.program, "uTexture"), 0);
    gl.uniform1f(gl.getUniformLocation(this.program, "uProgress"), progress);
    gl.uniform1f(gl.getUniformLocation(this.program, "uDir"), dir === "next" ? 1 : -1);

    gl.drawElements(gl.TRIANGLES, this.buffers.count, gl.UNSIGNED_SHORT, 0);
  }
}

let curlRenderer = null;

function getCurlRenderer() {
  if (!curlCanvas) return null;
  if (!curlRenderer) curlRenderer = new WebGLPageCurl(curlCanvas);
  return curlRenderer?.ready ? curlRenderer : null;
}

function animateWebGLCurl(textureCanvas, dir, duration, onComplete) {
  const renderer = getCurlRenderer();
  if (!renderer) return false;

  const dims = getPageRectForCanvas();
  renderer.resize(dims.cssW, dims.cssH, dims.dpr);
  renderer.uploadTexture(textureCanvas);

  curlCanvas.style.display = "block";
  flipLayer.classList.add("webglCurl");

  const start = performance.now();
  const ease = (t) => t < .5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

  const tick = (now) => {
    const raw = Math.min(1, (now - start) / duration);
    const eased = ease(raw);
    renderer.draw(eased, dir);
    if (raw < 1) {
      flipRaf = requestAnimationFrame(tick);
    } else {
      onComplete?.();
    }
  };

  renderer.draw(0.001, dir);
  flipRaf = requestAnimationFrame(tick);
  return true;
}

function fallbackCssFlip(currentIdx, nextIdx, dir, dur) {
  flipLayer.classList.remove("webglCurl");
  sheet.style.animation = "none";
  sheet.offsetHeight;
  sheet.style.animation = "";

  if (dir === "next") {
    sheet.style.transformOrigin = "left center";
    sheetFrontText.textContent = pages[currentIdx] ?? "";
    sheetBackText.textContent = pages[nextIdx] ?? "";
  } else {
    sheet.style.transformOrigin = "right center";
    sheetFrontText.textContent = pages[currentIdx] ?? "";
    sheetBackText.textContent = pages[nextIdx] ?? "";
  }

  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      flipLayer.classList.add("active", dir === "next" ? "flipNext" : "flipPrev");
    });
  });

  sheet.addEventListener("animationend", handleFlipEnd, { once: true });
  flipFallbackTimer = setTimeout(() => {
    if (animLock) resetFlipLayer();
  }, dur + 260);
}

function flipTo(nextIdx) {
  if (mode !== "book") return;
  if (!pages.length) buildPages();
  if (animLock) return;
  if (nextIdx === pageIndex) return;
  if (nextIdx < 0 || nextIdx >= pages.length) return;

  const currentIdx = pageIndex;
  const dir = nextIdx > currentIdx ? "next" : "prev";
  const reduced = reduceMotionMQ?.matches;

  if (reduced) {
    renderPage(nextIdx);
    return;
  }

  animLock = true;
  cancelFlipTimers();

  const textureCanvas = renderPageTexture(
    pages[currentIdx] ?? "",
    `${currentIdx + 1} / ${Math.max(1, pages.length)}`
  );

  flipLayer.style.display = "block";
  flipLayer.classList.remove("flipNext", "flipPrev", "active", "settling", "webglCurl");
  flipLayer.classList.add("active", dir === "next" ? "flipNext" : "flipPrev");

  renderPage(nextIdx);

  const dur = parseFloat(getComputedStyle(document.documentElement).getPropertyValue("--flipDur")) || 880;

  const usedWebGL = animateWebGLCurl(textureCanvas, dir, dur, () => {
    if (animLock) resetFlipLayer();
  });

  if (!usedWebGL) {
    fallbackCssFlip(currentIdx, nextIdx, dir, dur);
  } else {
    flipFallbackTimer = setTimeout(() => {
      if (animLock) resetFlipLayer();
    }, dur + 420);
  }
}

function goBookPrev() {
  flipTo(pageIndex - 1);
}

function goBookNext() {
  flipTo(pageIndex + 1);
}

// 글 박스 기준: 왼쪽 절반 두 번 = 이전 장, 오른쪽 절반 두 번 = 다음 장
let lastPageTap = { time: 0, side: null, x: 0, y: 0 };
let pointerStart = null;
let lastDoubleActionAt = 0;

function getPageActionSide(clientX) {
  const rect = pageShell.getBoundingClientRect();
  return clientX - rect.left < rect.width / 2 ? "prev" : "next";
}

function triggerPageSideAction(side) {
  if (mode !== "book" || animLock) return;
  if (side === "prev") goBookPrev();
  if (side === "next") goBookNext();
}

function handlePageDoubleAction(clientX, clientY, source = "pointer") {
  const now = Date.now();
  if (now - lastDoubleActionAt < 260) return;
  lastDoubleActionAt = now;
  const side = getPageActionSide(clientX);
  triggerPageSideAction(side);
  lastPageTap = { time: 0, side: null, x: 0, y: 0 };
}

// ------------------------------------------------------------
// TOC + episode navigation (✅ cover 포함 카드형)
// ------------------------------------------------------------
function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function getPlainExcerpt(content, limit = 88) {
  const plain = String(content ?? "").replace(/\s+/g, " ").trim();
  if (plain.length <= limit) return plain;
  return plain.slice(0, limit).trim() + "…";
}

function getReadingMinutes(content) {
  const chars = String(content ?? "").replace(/\s+/g, "").length;
  return Math.max(1, Math.round(chars / 720));
}

function renderToc() {
  toc.innerHTML = `
    <div class="tocHead">
      <div>
        <div class="sectionEyebrow">EPISODE ARCHIVE</div>
        <div class="tocTitle">목차</div>
      </div>
      <div class="tocSub">${NOVEL.episodes.length} Episodes</div>
    </div>

    <div class="tocGrid">
      ${NOVEL.episodes.map((ep, index) => {
        const epNo = String(index).padStart(2, "0");
        const excerpt = getPlainExcerpt(ep.content);
        const minutes = getReadingMinutes(ep.content);
        const coverStyle = ep.cover
          ? `background-image: linear-gradient(180deg, rgba(10,11,14,.08), rgba(10,11,14,.82)), url('${escapeHtml(ep.cover)}');`
          : "";
        return `
          <a class="tocCard" href="#${escapeHtml(ep.id)}" aria-label="${escapeHtml(ep.title)} 읽기">
            <div class="tocThumb" style="${coverStyle}">
              <div class="tocThumbGlow"></div>
              <div class="tocThumbMark">EP.${epNo}</div>
              <div class="tocThumbTitle">${escapeHtml(ep.title.replace(/^Ep\d+\s*-\s*/, ""))}</div>
            </div>
            <div class="tocInfo">
              <div class="tocEpTitle">${escapeHtml(ep.title)}</div>
              <div class="tocMeta">${escapeHtml(ep.date ?? "")} · 약 ${minutes}분</div>
              <div class="tocExcerpt">${escapeHtml(excerpt)}</div>
            </div>
          </a>
        `;
      }).join("")}
    </div>
  `;
}

function showEpisodeByHash() {
  const id = location.hash.replace("#", "");
  const idx = NOVEL.episodes.findIndex((e) => e.id === id);

  if (idx === -1) {
    reader.style.display = "none";
    toc.style.display = "block";
    return;
  }

  currentEpisodeIndex = idx;
  const ep = NOVEL.episodes[idx];

  toc.style.display = "none";
  reader.style.display = "block";

  epTitle.textContent = ep.title;
  epMeta.textContent = ep.date ? `업데이트: ${ep.date}` : "";
  epContent.textContent = normalizeReaderContent(ep.content);

  prevBtn.style.visibility = idx > 0 ? "visible" : "hidden";
  nextBtn.style.visibility = idx < NOVEL.episodes.length - 1 ? "visible" : "hidden";

  prevBtn.onclick = (e) => {
    e.preventDefault();
    location.hash = NOVEL.episodes[idx - 1].id;
  };
  nextBtn.onclick = (e) => {
    e.preventDefault();
    location.hash = NOVEL.episodes[idx + 1].id;
  };

  autoModeByDevice();
}

// ------------------------------------------------------------
// Mobile “Focus mode” : 책/스크롤 터치 시 컨트롤 숨김/표시
// - 모바일에서 하단바가 집중력 흐리는 문제 해결
// ------------------------------------------------------------
let focusTimer = null;
function enterFocus() {
  if (!isMobile()) return;
  document.body.classList.add("readingFocus");
}
function exitFocus() {
  document.body.classList.remove("readingFocus");
}
function pulseFocus() {
  if (!isMobile()) return;
  exitFocus();
  clearTimeout(focusTimer);
  focusTimer = setTimeout(() => enterFocus(), 1400);
}

// 본문 터치 시 컨트롤 잠깐 보여줬다가 다시 숨김
epContent.addEventListener("touchstart", pulseFocus, { passive:true });
bookStage.addEventListener("touchstart", pulseFocus, { passive:true });

// ------------------------------------------------------------
// UI wiring
// ------------------------------------------------------------
back.onclick = (e) => {
  e.preventDefault();
  location.hash = "";
};

modeScrollBtn.onclick = (e) => {
  e.preventDefault();
  setMode("scroll");
};
modeBookBtn.onclick = (e) => {
  e.preventDefault();
  setMode("book");
};

pagePrevBtn.onclick = (e) => {
  e.preventDefault();
  goBookPrev();
};
pageNextBtn.onclick = (e) => {
  e.preventDefault();
  goBookNext();
};

mPrev.onclick = (e) => {
  e.preventDefault();
  if (mode === "book") goBookPrev();
  else window.scrollBy({ top: -window.innerHeight * 0.75, behavior: "smooth" });
};
mNext.onclick = (e) => {
  e.preventDefault();
  if (mode === "book") goBookNext();
  else window.scrollBy({ top: window.innerHeight * 0.75, behavior: "smooth" });
};
mMode.onclick = (e) => {
  e.preventDefault();
  const next = mode === "scroll" ? "book" : "scroll";
  setMode(next);
};

fontMinus?.addEventListener("click", () => {
  readerPrefs.font -= 1;
  applyReaderPrefs(true);
});
fontPlus?.addEventListener("click", () => {
  readerPrefs.font += 1;
  applyReaderPrefs(true);
});
fontReset?.addEventListener("click", () => {
  readerPrefs = { ...DEFAULT_READER_PREFS };
  applyReaderPrefs(true);
});
lineMinus?.addEventListener("click", () => {
  readerPrefs.line -= 0.1;
  applyReaderPrefs(true);
});
linePlus?.addEventListener("click", () => {
  readerPrefs.line += 0.1;
  applyReaderPrefs(true);
});

// keyboard (desktop)
window.addEventListener("keydown", (e) => {
  if (mode !== "book") return;
  if (reader.style.display === "none") return;
  if (e.key === "ArrowRight") goBookNext();
  if (e.key === "ArrowLeft") goBookPrev();
});

// swipe
let touchX = null;
bookStage.addEventListener(
  "touchstart",
  (e) => {
    if (mode !== "book") return;
    touchX = e.touches[0].clientX;
  },
  { passive: true }
);

bookStage.addEventListener(
  "touchend",
  (e) => {
    if (mode !== "book") return;
    if (touchX === null) return;
    const endX = e.changedTouches[0].clientX;
    const dx = endX - touchX;
    touchX = null;

    const threshold = 50;
    if (dx < -threshold) goBookNext();
    else if (dx > threshold) goBookPrev();
  },
  { passive: true }
);

// double click / double tap on page half zones
pageShell.addEventListener("pointerdown", (e) => {
  if (mode !== "book") return;
  pointerStart = { x: e.clientX, y: e.clientY, time: Date.now() };
});

pageShell.addEventListener("pointerup", (e) => {
  if (mode !== "book" || !pointerStart) return;

  const dx = Math.abs(e.clientX - pointerStart.x);
  const dy = Math.abs(e.clientY - pointerStart.y);
  const held = Date.now() - pointerStart.time;
  pointerStart = null;

  // Do not treat swipes, drags, or long presses as double taps.
  if (dx > 18 || dy > 18 || held > 520) return;

  const now = Date.now();
  const side = getPageActionSide(e.clientX);
  const sameZone = lastPageTap.side === side;
  const closeEnough = Math.abs(e.clientX - lastPageTap.x) < 90 && Math.abs(e.clientY - lastPageTap.y) < 90;
  const fastEnough = now - lastPageTap.time < 420;

  if (sameZone && closeEnough && fastEnough) {
    e.preventDefault();
    handlePageDoubleAction(e.clientX, e.clientY, "pointer");
    return;
  }

  lastPageTap = { time: now, side, x: e.clientX, y: e.clientY };
});

pageShell.addEventListener("dblclick", (e) => {
  if (mode !== "book") return;
  e.preventDefault();
  handlePageDoubleAction(e.clientX, e.clientY, "dblclick");
});

// resize reflow
let resizeTimer = null;
window.addEventListener("resize", () => {
  if (mode !== "book") return;
  clearTimeout(resizeTimer);
  resizeTimer = setTimeout(() => {
    const keep = pageIndex;
    buildPages();
    renderPage(clamp(keep, 0, Math.max(0, pages.length - 1)));
  }, 140);
});

// device change
mobileMQ.addEventListener?.("change", () => autoModeByDevice());

// ------------------------------------------------------------
// Init
// ------------------------------------------------------------
applyReaderPrefs(false);
renderToc();
window.addEventListener("hashchange", showEpisodeByHash);
showEpisodeByHash();

enterFocus();

// ============================================================
// v6 VERIFIED PAGE CURL OVERRIDE
// - WebGL 대신 검증 가능한 DOM+Canvas segmented mesh 방식 사용
// - 페이지 텍스처를 36개 세로 조각으로 나누고 각 조각을 3D 회전/이동시켜
//   실제 종이가 휘며 넘어가는 것처럼 보이게 한다.
// ============================================================
let stripCurlRaf = null;
let stripCurlCleanupTimer = null;

function easeOutCubicV6(t) {
  return 1 - Math.pow(1 - t, 3);
}
function easeInOutCubicV6(t) {
  return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
}
function clamp01V6(v) {
  return Math.max(0, Math.min(1, v));
}
function clearStripCurlV6() {
  if (stripCurlRaf) cancelAnimationFrame(stripCurlRaf);
  stripCurlRaf = null;
  clearTimeout(stripCurlCleanupTimer);
  stripCurlCleanupTimer = null;
  const old = flipLayer.querySelector(".stripCurlLayer");
  if (old) old.remove();
  flipLayer.classList.remove("stripCurlMode", "flipNext", "flipPrev", "active", "settling", "webglCurl");
  flipLayer.style.removeProperty("--curlRidgeX");
  flipLayer.style.removeProperty("--curlRidgeOpacity");
  flipLayer.style.removeProperty("--curlFloorShadow");
  flipLayer.style.display = "none";
  if (sheet) {
    sheet.style.transform = "";
    sheet.style.transformOrigin = "left center";
  }
  if (curlCanvas) curlCanvas.style.display = "none";
  animLock = false;
}
function makeTextureCanvasV6(text, pageNoText) {
  if (typeof renderPageTexture === "function") return renderPageTexture(text, pageNoText);
  const rect = pageShell.getBoundingClientRect();
  const dpr = Math.max(1, Math.min(2, window.devicePixelRatio || 1));
  const c = document.createElement("canvas");
  c.width = Math.max(1, Math.round(rect.width * dpr));
  c.height = Math.max(1, Math.round(rect.height * dpr));
  const ctx = c.getContext("2d");
  ctx.scale(dpr, dpr);
  ctx.fillStyle = "#11100d";
  ctx.fillRect(0, 0, rect.width, rect.height);
  ctx.fillStyle = "#ebe5d8";
  ctx.font = "17px system-ui, sans-serif";
  String(text || "").split("\n").slice(0, 24).forEach((line, i) => ctx.fillText(line, 18, 24 + i * 30));
  return c;
}
function createStripLayerV6(textureCanvas, dir) {
  const rect = pageShell.getBoundingClientRect();
  const layer = document.createElement("div");
  layer.className = "stripCurlLayer";
  const w = Math.max(1, rect.width);
  const h = Math.max(1, rect.height);
  const stripCount = Math.min(46, Math.max(28, Math.round(w / 13)));
  const stripW = w / stripCount;
  const dataUrl = textureCanvas.toDataURL("image/png");
  for (let i = 0; i < stripCount; i += 1) {
    const s = document.createElement("div");
    s.className = "stripCurlPiece";
    s.dataset.i = String(i);
    s.style.left = `${i * stripW}px`;
    s.style.width = `${Math.ceil(stripW) + 1}px`;
    s.style.backgroundImage = `url(${dataUrl})`;
    s.style.backgroundSize = `${w}px ${h}px`;
    s.style.backgroundPosition = `${-i * stripW}px 0px`;
    s.style.transformOrigin = dir === "next" ? "left center" : "right center";
    layer.appendChild(s);
  }
  return { layer, w, h, stripCount, stripW };
}
function animateStripCurlV6(textureCanvas, dir, duration, done) {
  clearStripCurlV6();
  flipLayer.style.display = "block";
  flipLayer.classList.add("active", "stripCurlMode", dir === "next" ? "flipNext" : "flipPrev");
  const { layer, w, stripCount, stripW } = createStripLayerV6(textureCanvas, dir);
  flipLayer.appendChild(layer);
  const pieces = Array.from(layer.children);
  const started = performance.now();
  const direction = dir === "next" ? -1 : 1;
  const reverseIndex = dir === "next";

  function frame(now) {
    const raw = clamp01V6((now - started) / duration);
    const p = easeInOutCubicV6(raw);
    const ridgeU = dir === "next" ? 1 - p : p;
    flipLayer.style.setProperty("--curlRidgeX", `${ridgeU * 100}%`);
    flipLayer.style.setProperty("--curlRidgeOpacity", String(Math.sin(Math.PI * raw) * 0.95));
    flipLayer.style.setProperty("--curlFloorShadow", String(0.18 + Math.sin(Math.PI * raw) * 0.46));

    pieces.forEach((piece, index) => {
      const u = (index + 0.5) / stripCount;
      // 다음 장은 오른쪽 조각부터, 이전 장은 왼쪽 조각부터 말려 들어간다.
      const frontOrder = reverseIndex ? 1 - u : u;
      const delay = frontOrder * 0.42;
      const local = clamp01V6((raw - delay) / (1 - delay * 0.72));
      const q = easeOutCubicV6(local);
      const wave = Math.sin(q * Math.PI);
      const originalX = index * stripW;
      const travel = direction * (w * (0.18 + 0.82 * p) * (reverseIndex ? (1 - u * 0.18) : (0.82 + u * 0.18)));
      const curlPull = direction * wave * (42 + 64 * Math.abs(u - 0.5));
      const z = wave * (74 + 36 * (1 - Math.abs(u - 0.5) * 2));
      const rot = direction * q * (120 + 58 * p + 18 * wave);
      const skew = direction * wave * (7 - Math.abs(u - 0.5) * 4);
      const scaleY = 1 - wave * 0.035;
      const opacity = raw > 0.94 ? Math.max(0, 1 - (raw - 0.94) / 0.06) : 1;
      piece.classList.toggle("backSide", q > 0.52);
      piece.style.zIndex = String(2000 + Math.round(z) + (reverseIndex ? stripCount - index : index));
      piece.style.opacity = String(opacity);
      piece.style.setProperty("--pieceShade", String(0.10 + wave * 0.50));
      piece.style.transform = `translate3d(${travel + curlPull}px, ${Math.sin(q * Math.PI * 2) * 1.8}px, ${z}px) rotateY(${rot}deg) rotateZ(${skew}deg) scaleY(${scaleY})`;
    });

    if (raw < 1) {
      stripCurlRaf = requestAnimationFrame(frame);
    } else {
      done?.();
    }
  }
  stripCurlRaf = requestAnimationFrame(frame);
  stripCurlCleanupTimer = setTimeout(() => done?.(), duration + 520);
}

// 기존 flipTo를 실제로 작동 확인 가능한 곡면 종이 넘김 방식으로 덮어쓴다.
function flipTo(nextIdx) {
  if (mode !== "book") return;
  if (!pages.length) buildPages();
  if (animLock) return;
  if (nextIdx === pageIndex) return;
  if (nextIdx < 0 || nextIdx >= pages.length) return;

  const currentIdx = pageIndex;
  const dir = nextIdx > currentIdx ? "next" : "prev";
  const reduced = reduceMotionMQ?.matches;
  if (reduced) {
    renderPage(nextIdx);
    return;
  }

  animLock = true;
  cancelFlipTimers?.();
  const textureCanvas = makeTextureCanvasV6(
    pages[currentIdx] ?? "",
    `${currentIdx + 1} / ${Math.max(1, pages.length)}`
  );

  // 다음 페이지를 먼저 깔고, 그 위에서 현재 페이지 텍스처가 휘며 넘어간다.
  renderPage(nextIdx);
  const dur = 1180;
  let finished = false;
  function finish() {
    if (finished) return;
    finished = true;
    clearStripCurlV6();
  }
  animateStripCurlV6(textureCanvas, dir, dur, finish);
}

// 개발/검수용 상태 노출: 콘솔에서 window.__readerDebug() 호출 가능
window.__readerDebug = function () {
  return {
    mode,
    currentEpisodeIndex,
    pageIndex,
    pages: pages.length,
    animLock,
    hasStripLayer: Boolean(flipLayer.querySelector(".stripCurlLayer")),
    flipLayerClass: flipLayer.className,
    pageTextLength: pageText.textContent.length,
  };
};
